        // Key: sum (a^3 + b^3)
        // Value: A list of pairs (a, b) that produce this sum.
        Map<Long, List<long[]>> sumsMap = new HashMap<>();

        // Determine the maximum value for 'a' or 'b'.
        // Since a <= b and a^3 + b^3 <= n, we have 2*a^3 <= n, so a^3 <= n/2.
        // Or, more simply, b^3 <= n, so b <= n^(1/3).
        // Since a >= 1, we only need to iterate 'a' up to the point where 
        // the smallest possible sum (a^3 + a^3) exceeds n.
        // 2 * a^3 <= n  => a^3 <= n/2
        long max_a_limit_cubed = n / 2;
        long max_a = (long) Math.pow(max_a_limit_cubed, 1.0/3.0);

        // Iterate through all possible pairs (a, b) such that 1 <= a <= b and a^3 + b^3 <= n.
        for (long a = 1; a <= max_a; a++) {
            long a3 = a * a * a;

            // Start b from a (since a <= b)
            // b^3 <= n - a^3
            long max_b_cubed = n - a3;
            long max_b = (long) Math.pow(max_b_cubed, 1.0/3.0);

            // We must ensure b >= a
            long start_b = Math.max(a, 1);

            for (long b = start_b; b <= max_b; b++) {
                long b3 = b * b * b;
                long sum = a3 + b3;

