class Solution {
    /**
     * Finds all "good integers" less than or equal to n.
     * A positive integer x is a "good integer" if there are at least two different pairs (a, b)
     * with 1 <= a <= b such that x = a^3 + b^3.
     *
     * @param n The upper limit.
     * @return An array containing all good integers less than or equal to n, in ascending order.
     */
    public static long[] solve(long n) {
        // Map to store the sums (a^3 + b^3) and the number of ways to form that sum.
        // Key: the sum x
        // Value: a list of pairs (represented by a single long or similar, but we only need the count)
        Map<Long, Integer> sumCounts = new HashMap<>();

        // Determine the maximum value for 'a' and 'b'.
        // Since a >= 1 and b >= a, the smallest possible sum for a fixed 'a' is a^3 + a^3 = 2*a^3.
        // The largest possible sum is when a=1 and b is such that 1^3 + b^3 <= n, so b^3 <= n - 1.
        // If a=1, b <= (n-1)^(1/3).
        // A safe upper bound for 'b' (and thus 'a') is when a^3 + a^3 <= n, so 2*a^3 <= n, a^3 <= n/2.
        // Since we iterate through all pairs (a, b) with a <= b, we only need to ensure b^3 <= n.

        // Max b such that b^3 <= n
        long maxB = (long) Math.floor(Math.pow(n, 1.0 / 3.0));

        // Iterate over possible values for a
        for (long a = 1; a <= maxB; a++) {
            long aCubed = a * a * a;

            // Iterate over possible values for b, where b >= a
            // We stop when a^3 + b^3 > n, which means b^3 > n - a^3.
            // b > (n - a^3)^(1/3)
            for (long b = a; ; b++) {
                long bCubed = b * b * b;

                long currentSum = aCubed + bCubed;

                if (currentSum > n) {
                    break; // Stop iterating b for the current a
                }

                // Increment the count for this sum
                sumCounts.put(currentSum, sumCounts.getOrDefault(currentSum, 0) + 1);
            }
        }

        // Collect all good integers (those with count >= 2)
        List<Long> goodIntegers = new ArrayList<>();
        for (Map.Entry<Long, Integer> entry : sumCounts.entrySet()) {
            if (entry.getValue() >= 2) {
                goodIntegers.add(entry.getKey());
            }
        }

        // Sort the results in ascending order
        Collections.sort(goodIntegers);

        // Convert List<Long> to long[]
        long[] result = new long[goodIntegers.size()];
        for (int i = 0; i < goodIntegers.size(); i++) {
            result[i] = goodIntegers.get(i);
        }

        return result;
    }
}
