        // Key: sum (x)
        // Value: count of distinct pairs (a, b) such that a^3 + b^3 = x
        Map<Long, Integer> sumCounts = new HashMap<>();

        // Since a and b are positive integers and a <= b,
        // a^3 + b^3 <= n.
