        for (long a = 1; a * a * a <= n; a++) {
            // Start b from a to ensure a <= b
            for (long b = a; ; b++) {
                long cubeA = a * a * a;
                long cubeB = b * b * b;

                long sum = cubeA + cubeB;

                if (sum > n) {
                    // Since b is increasing, subsequent sums will also be > n
                    break;
                }

                // Count the occurrences of this sum
                sumCounts.put(sum, sumCounts.getOrDefault(sum, 0) + 1);
            }
        }

        // Collect all "good numbers" (those with count >= 2)
        List<Long> goodNumbersList = new ArrayList<>();
        for (Map.Entry<Long, Integer> entry : sumCounts.entrySet()) {
            if (entry.getValue() >= 2) {
                goodNumbersList.add(entry.getKey());
            }
        }

        // Sort the good numbers in ascending order
        Collections.sort(goodNumbersList);

        // Convert the list to a long array
        long[] result = new long[goodNumbersList.size()];
        for (int i = 0; i < goodNumbersList.size(); i++) {
            result[i] = goodNumbersList.get(i);
        }

        return result;
    }
